// // This module compares two 4-bit numbers and outputs whether the first number is less than, equal to, or greater than the second number.
module magnitude_comparator(
	input wire [3:0] a,
	input wire [3:0] b,
	output wire a_gt_b,
	output wire a_eq_b,
	output wire a_lt_b
);assign a_gt_b = (a > b);
	assign a_eq_b = (a == b);
	assign a_lt_b = (a < b);
endmodule
